const items = $input.all();
let articles = [];

for (const item of items) {

  // Handle NewsAPI response
  if (item.json.articles) {
    for (const a of item.json.articles) {
      articles.push({
        title: a.title || '',
        url: a.url || '',
        source: a.source?.name || 'NewsAPI',
        publishedAt: a.publishedAt || '',
        content: a.content || a.description || ''
      });
    }
  }

  // Handle RSS Read response (Google News)
  if (item.json.title && item.json.link) {
    articles.push({
      title: item.json.title || '',
      url: item.json.link || '',
      source: 'Google News',
      publishedAt: item.json.pubDate || '',
      content: item.json.content || item.json.contentSnippet || item.json.summary || ''
    });
  }
}

// Deduplicate by title
const seen = new Set();
const unique = articles.filter(a => {
  const key = a.title.toLowerCase().trim();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Filter for India-relevant articles only
const indiaKeywords = [
  'india', 'indian', 'irdai', 'lic', 'mumbai', 'delhi',
  'rupee', 'crore', 'lakh', 'hdfc life', 'icici prudential',
  'sbi life', 'max life', 'bajaj allianz', 'kotak life',
  'tata aia', 'aditya birla', 'pnb metlife', 'reliance life',
  'icici life', 'birla sunlife', 'star union', 'exide life',
  'future generali', 'canara hsbc', 'pramerica', 'aegon life'
];

const indiaFiltered = unique.filter(a => {
  const text = (a.title + ' ' + a.content).toLowerCase();
  return indiaKeywords.some(keyword => text.includes(keyword));
});

// Filter last 7 days
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const monthFiltered = indiaFiltered.filter(a => {
  if (!a.publishedAt) return false;
  const articleDate = new Date(a.publishedAt);
  return articleDate >= sevenDaysAgo;
});

// Sort by date — newest first
monthFiltered.sort((a, b) => {
  const dateA = new Date(a.publishedAt || 0);
  const dateB = new Date(b.publishedAt || 0);
  return dateB - dateA;
});

// Limit to 15 most recent articles
const limited = monthFiltered.slice(0, 15);
return limited.map(a => ({ 
  json: {
    title: a.title,
    url: a.url,
    source: a.source,
    publishedAt: a.publishedAt,
    content: a.content
  }
}));

