=You are a professional insurance industry analyst in India. Summarise the following news article in exactly 5 clear numbered points. Do not miss any key information. Each point must be one concise sentence. Return only the 5 numbered points, nothing else. No introduction, no conclusion.

Title: {{ $json.title }}

Content: {{ $json.content }}

parameters.jsCode:
const items = $input.all();
const rawItems = items.map(i => ({
  title: i.json.title || '',
  url: i.json.url || '',
  source: i.json.source || '',
  publishedAt: i.json.publishedAt || '',
  text: i.json.text || ''
}));

const DIGEST_TITLE = "Life Insurance Industry — India News Digest";
const ACCENT_COLOR = "#1a3c5e";
const SHOW_SOURCE = true;
const SHOW_DATE = true;

const today = new Date().toLocaleDateString('en-IN', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

let htmlContent = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body { font-family: Calibri, Arial, sans-serif; max-width: 820px; margin: 0 auto; padding: 30px; color: #222; }
  h1 { color: #1a3c5e; font-size: 22pt; border-bottom: 3px solid #1a3c5e; padding-bottom: 12px; margin-bottom: 6px; }
  .date { color: #888; font-size: 11pt; margin-top: 0; margin-bottom: 30px; }
  .article { margin-bottom: 40px; padding: 24px; border-left: 4px solid #1a3c5e; background: #f8f9fb; }
  .article-title { color: #1a3c5e; font-size: 14pt; font-weight: bold; margin: 0 0 6px 0; line-height: 1.4; }
  .meta { color: #999; font-size: 10pt; margin: 0 0 16px 0; }
  ol { margin: 0 0 16px 0; padding-left: 20px; font-size: 12pt; }
  ol li { margin-bottom: 8px; line-height: 1.6; color: #333; }
  .article-link { margin: 12px 0 0 0; padding-top: 10px; border-top: 1px solid #e0e4ea; font-size: 11pt; }
  .article-link a { color: #1a3c5e; text-decoration: underline; word-break: break-all; }
  .footer { color: #bbb; font-size: 9pt; text-align: center; margin-top: 40px; border-top: 1px solid #eee; padding-top: 16px; }
</style>
</head>
<body>
<h1>${DIGEST_TITLE}</h1>
<p class="date">${today}</p>
`;

for (let index = 0; index < rawItems.length; index++) {
  const article = rawItems[index] || {};

  const title = (article.title || article.json?.title || 'No Title').toString();
  const url = (article.url || article.json?.url || '').toString();
  const source = (article.source || article.json?.source || '').toString();
  const summaryText = (article.text || article.json?.text || '').toString();

  const rawDate = article.publishedAt || article.json?.publishedAt || '';
  const publishedAt = rawDate ? new Date(rawDate).toLocaleDateString('en-IN') : '';

  const metaLine = [
    SHOW_SOURCE && source ? source : null,
    SHOW_DATE && publishedAt ? publishedAt : null
  ].filter(Boolean).join(' | ');

  const lines = summaryText.split('\n');
  const pointLines = lines.filter(line => {
    if (!line || typeof line !== 'string') return false;
    return line.trim().match(/^\d+[\.\)]/);
  });

  const pointsHtml = pointLines.length > 0
    ? pointLines.map(line => {
        const clean = line.replace(/^\d+[\.\)]\s*/, '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        return `<li>${clean}</li>`;
      }).join('')
    : `<li>${summaryText.replace(/&/g,'&amp;')}</li>`;

  htmlContent += `
  <div class="article">
    <p class="article-title">${index + 1}. ${title.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</p>
    ${metaLine ? `<p class="meta">${metaLine}</p>` : ''}
    <ol>${pointsHtml}</ol>
    <p class="article-link">
      <a href="${url}">Read full article</a>
    </p>
  </div>`;
}

htmlContent += `
<p class="footer">Auto-generated — Life Insurance News Digest</p>
</body>
</html>`;

const fileName = `Life_Insurance_Digest_${new Date().toISOString().slice(0,10)}.doc`;
const base64Content = Buffer.from(htmlContent, 'utf8').toString('base64');

return [{
  json: {
    htmlBody: htmlContent,
    today,
    articleCount: rawItems.length,
    fileName
  },
  binary: {
    attachment: {
      data: base64Content,
      mimeType: 'application/msword',
      fileName: fileName,
      fileExtension: 'doc'
    }
  }
}];
